// Ask the agent a math question
async function main() {
  try {
    console.log('Starting agent generation...');
    const response = await agent.generate('What is 15 multiplied by 7?');

    console.log('Response received:');
    console.log('  - Text:', response.text);
    console.log('  - Finish reason:', response.finishReason);
    console.log('  - Tool calls:', response.toolCalls?.length || 0);
    console.log('  - Tool results:', response.toolResults?.length || 0);
    console.log('  - Steps:', response.steps?.length || 0);

    // Log tool calls details
    if (response.toolCalls && response.toolCalls.length > 0) {
      console.log('Tool calls details:');
      response.toolCalls.forEach((call, i) => {
        console.log(`  Call ${i + 1}:`, JSON.stringify(call.payload, null, 2));
      });
    }

    // Log tool results details
    if (response.toolResults && response.toolResults.length > 0) {
      console.log('Tool results details:');
      response.toolResults.forEach((result, i) => {
        console.log(`  Result ${i + 1}:`, JSON.stringify(result, null, 2));
      });
    }

    // Write the output to output.log
    const fs = require('fs');
    fs.writeFileSync('/home/user/calculator-agent/output.log', response.text);

    console.log('\nResponse written to output.log');
  } catch (error) {
    console.error('Error:', error);
    process.exit(1);
  }
}

